import { useState } from "react";
import { motion } from "framer-motion";
import { design } from "../../design/authDesign";


/* ===============================
   🚀 COMPONENT
================================= */

const AdminLogin = () => {
  const [form, setForm] = useState({
    email: "",
    password: "",
  });

  const handleChange = (e) => {
    setForm({ ...form, [e.target.name]: e.target.value });
  };

  const handleSubmit = (e) => {
    e.preventDefault();
    console.log("Form Data:", form);
  };

  return (
    <motion.div
      {...design.animation.container}
      className={`${design.colors.background} ${design.layout.container}`}
    >
      <motion.div
        {...design.animation.card}
        className={`${design.colors.card} ${design.layout.card}`}
      >
        {/* Title */}
        <div className="text-center mb-8">
          <h2 className={`text-3xl font-bold ${design.colors.title}`}>
            Admin Login
          </h2>
          <p className={`text-sm mt-2 ${design.colors.subtitle}`}>
            Enter your credentials to access dashboard
          </p>
        </div>

        {/* Form */}
        <form onSubmit={handleSubmit} className="space-y-5">
          <input
            type="email"
            name="email"
            placeholder="Admin Email"
            value={form.email}
            onChange={handleChange}
            className={`${design.layout.input} ${design.colors.inputBg} ${design.colors.inputBorder} ${design.colors.inputText}`}
          />

          <input
            type="password"
            name="password"
            placeholder="Password"
            value={form.password}
            onChange={handleChange}
            className={`${design.layout.input} ${design.colors.inputBg} ${design.colors.inputBorder} ${design.colors.inputText}`}
          />

          <button
            type="submit"
            className={`${design.layout.button} ${design.colors.button} ${design.colors.buttonHover} text-white`}
          >
            Sign In
          </button>
        </form>
      </motion.div>
    </motion.div>
  );
};

export default AdminLogin;
